mapper.select:
SELECT u.id, u.username, u.status, u.created_at, COALESCE(creator.username, 'Unknown') AS creator, u.updated_at, COALESCE(updater.username, 'Unknown') AS updater FROM sys_user u LEFT JOIN sys_user creator ON u.created_by = creator.id LEFT JOIN sys_user updater ON u.updated_by = updater.id
AND u.username LIKE #{username} || '%'
${ew.customSqlSegment}
